INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (11, 0, 0, 8, "ならこいつはどうだい？\nトーゴクでも\n滅多にお目にかかれない逸品だよ。", 120831, 0, 301, 301009, 0.5, 0);
