INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (11, 0, 1, 6, "そうだ、シノブさん！\nアカリたちの今年の運勢、\n占ってほしいな。", 100611, 0, 505, 505066, 0.5, 0);
