INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (11, 0, 1, 8, "クリスティーナ！\nあなたはいったいどの面下げて\n私たちの前に……", 103731, 0, 506, 506013, 0.5, 0);
