INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (11, 0, 1, 8, "まあまあ、\nトモちゃんもクリスちゃんも。\nせっかくの新年会なんだから……", 104731, 0, 506, 506018, 0.5, 0);
