INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (11, 0, 1, 5, "さすがショーグン。\nこれなら天下統一も目前デス！", 103031, 0, 513, 513072, 0.5, 0);
