INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (11, 0, 1, 6, "新年といういい機会だ。\n今年の抱負を発表しようじゃないか。", 105331, 0, 513, 513077, 0.5, 0);
