INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (11, 0, 1, 7, "確かに沢山の人が来られてますね。\nプロデューサーさんも\n楽しそうにしてました。", 104211, 0, 515, 515047, 0.5, 0);
